#include <bits/stdc++.h>
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);cin.tie(0);cout.tie(0);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
CI m=998244353;
CI MAXN=1e6+5,MAXM=5e6+5;
int f[MAXN];
int d;
char c[MAXN];
int l[MAXM],r[MAXM],t;
int v[MAXM];
int dfs(int x)
{
	long long res=1;
	if(v[l[x]])
	{
		res*=v[l[x]];
	}
	else
	{
		res*=dfs(l[x]);
	}
	if(v[r[x]])
	{
		res*=v[r[x]];
	}
	else
	{
		res*=dfs(r[x]);
	}
	res++;
	res%=m;
	return res;
}
int solve()
{
	cin>>d>>c;
	if(c[0]=='1')
	{
		return f[d];
	}
	int p=1;
	t=1;
	FOR(i,1,d-1)
	{
		l[p]=++t;
		r[p]=++t;
		if(c[i]=='1')// 走右儿子
		{
			v[l[p]]=f[d-i]+1;
			if(i==d-1)
			{
				v[r[p]]=1;
			}
			else
			{
				v[r[p]]=0;
			}
			p=r[p];
		}
		else// 走左儿子
		{
			v[r[p]]=f[d-i-1]+1;
			if(i==d-1)
			{
				v[l[p]]=1;
			}
			else
			{
				v[l[p]]=0;
			}
			p=l[p];
		}
	}
	return (dfs(1)+m-1)%m;
}
signed main(void)
{
    int T;
	IOS;
	f[1]=1;
	FOR(i,2,1e6)
	{
		f[i]=1ll*(f[i-1]+1)*(f[i-1]+1)%m;
	}

	cin>>T;
	wh(T--)
	{
		cout<<solve()<<'\n';
	}
	return false;
}
